import{u as k,_ as d}from"./BaseSection-D52_z1w9.js";import{i}from"./siteContent-Mdeep8yA.js";import{_ as b}from"./HeroSection-BjukhYWM.js";import{H as z}from"./HomeImageTextBlock-BZ0S0dIG.js";import{N as p}from"./NextExpert-d-uR1x-0.js";import{_,o as a,c as s,a as l,u as e,F as h,r as o,w as g,d as v,m as w,b as r,t as c,h as S}from"./index-CO1Ke-31.js";import"./BaseButton-CZpagXDj.js";import"./RichText-DD9KrJzC.js";const V=[{id:1,imageUrl:"/images/infoblocks/grunerstar.webp",imageAlt:"Visuelle Veranschaulichung von Grüner Star",imagePosition:"right",heading:"Grüner Star",body:"Das Glaukom, auch Grüner Star genannt, bezeichnet eine Reihe verschiedener Veränderungen, die mit einem individuell erhöhten Augeninnendruck zusammenhängen. Die Folgen daraus können irreversible – also nicht mehr rückgängig zu machende – Schädigungen von Nervenfasern sein. Aufgrund dessen kann es im weiteren Verlauf zur dauerhaften Einschränkung der Sehkraft und / oder Ausfällen des Sichtsfeldes (im oberen Foto als schwarze Flecken dargestellt) kommen."},{id:2,imageUrl:"/images/infoblocks/grauerstar.webp",imageAlt:"Visuelle Veranschaulichung von Grauer Star",imagePosition:"left",heading:"Grauer Star",body:"Als Katarakt oder Grauen Star bezeichnet man eine Trübung der Augenlinse, welche die Sehkraft sowie das Farb- und Kontrastsehen reduzieren kann. In der Regel kann ein Grauer Star durch einen medizinischen Eingriff behandelt werden, bei dem die eingetrübte Augenlinse durch eine künstliche Linse (Intraokularlinse) ausgetauscht wird."},{id:3,imageUrl:"/images/infoblocks/amd.webp",imageAlt:"Visuelle Veranschaulichung von Makuladengeneration",imagePosition:"right",heading:"Makuladegeneration (AMD) ",body:"Die Makuladegeneration ist eine Erkrankung der Netzhaut, bei der die empfindlichen Sinneszellen dauerhaft in ihrer Funktion eingeschränkt sind. Es gibt unterschiedliche Ursachen für eine Makuladegeneration. Im wesentlichen unterscheidet man dabei zwischen der trockenen und der feuchten Form. Bei der trockenen Makuladegeneration sinkt die Leistungsfähigkeit der Sinneszellen in der Netzhaut durch Ablagerungen (Drusen) auf der Netzhaut, bei der feuchten durch Einblutungen. Die trockene Form der Makuladegeneration verläuft in der Regel deutlich langsamer als die feuchte Makuladegeneration, bei der sich die Sehkraft sehr rapide reduzieren kann."},{id:4,imageUrl:"/images/infoblocks/netzhautablosung.webp",imageAlt:"Visuelle Veranschaulichung von Netzhautablösung",imagePosition:"left",heading:"Netzhautablösung",body:"Als Netzhautablösung bezeichnet man eine Ablösung des inneren Anteils der Netzhaut von ihrer Versorgungsschicht. Eine Netzhautablösung stellt einen akuten augenärztlichen Notfall dar, der umgehend behandelt werden muss. Eine nicht rechtzeitig behandelte Netzhautablösung kann gravierende Auswirkungen auf die Sehkraft haben und führt sehr häufig zu größeren Sichtfeldausfällen. Die häufigste Ursache für eine Netzhautablösung ist ein Riss in der Netzhaut (z. B. durch eine starke Kurzsichtigkeit oder einen Unfall), bei dem Flüssigkeit zwischen die innere Netzhaut und die Versorgungsschicht läuft."},{id:5,imageUrl:"/images/infoblocks/diabetisch.webp",imageAlt:"Visuelle Veranschaulichung von Diabetische Retinopathie",imagePosition:"right",heading:"Diabetische Retinopathie",body:"Die diabetische Retinopathie (Retinopathia diabetica) ist eine durch die Zuckerkrankheit (Diabetes mellitus) hervorgerufene Veränderung der Netzhaut des Auges. Die zunehmende Schädigung kleiner Blutgefäße verursacht eine zunächst unbemerkte Schädigung der Netzhaut. Als Hauptursache gilt eine langjährige Zuckerkrankheit, die ggf. durch einen falsch eingestellten oder schlecht kontrollierten Blutzuckerspiegel zusätzlich begünstigt werden kann."},{id:6,imageUrl:"/images/infoblocks/pigmentosa.webp",imageAlt:"Visuelle Veranschaulichung von Retinopathie Pigmentosa",imagePosition:"left",heading:"Retinopathie Pigmentosa",body:"Als Retinopathie Pigmentosa (RP) bezeichnet man eine durch Vererbung oder spontane Mutation entstehende Netzhauterkrankung, bei der die Funktion der empfindlichen Sinneszellen in der Netzhaut allmählich nachlässt. Häufig beginnt die RP im Randbereich der Netzhaut, sodass das Sichtfeld eingeschränkt wird und eine Art Tunnelblick entsteht. Die Betroffenen verfügen in diesem Stadium im zentralen Bereich noch über die volle Sehkraft und können problemlos scharf sehen (siehe Foto). Erst in einem späteren Stadium – in dem auch die zentralen Sinneszellen betroffen sein können – kann auch diese zentrale Sehkraft dauerhaft eingeschränkt werden."}],A={class:"usefulLinks-headline"},N={class:"useful-links"},y=["href"],P={__name:"InfoAndPartnersView",setup(R){const m=V.map(u=>({...u,imageUrl:"/LVK/"+u.imageUrl.replace(/^\//,"")}));return k({title:"Info & Partner",description:"Informationen über das Low-Vision-Kreis-Partnernetzwerk und Möglichkeiten zur Zusammenarbeit."}),(u,t)=>(a(),s("div",null,[l(b,{headline:e(i).hero.headline,body:e(i).hero.body,backgroundImage:e(i).hero.backgroundImage,overlayOpacity:e(i).hero.overlayOpacity},null,8,["headline","body","backgroundImage","overlayOpacity"]),(a(!0),s(h,null,o(e(m),(n,f)=>(a(),v(d,{key:n.id,variant:f%2===0?"default":"alt"},{default:g(()=>[l(z,w({ref_for:!0},n),null,16)]),_:2},1032,["variant"]))),128)),l(p),l(d,{variant:"alt"},{default:g(()=>[r("h2",A,c(e(i).usefulLinks.headline),1),r("ul",N,[(a(!0),s(h,null,o(e(i).usefulLinks.links,n=>(a(),s("li",{key:n.href,class:"useful-links__item"},[r("a",{href:n.href,class:"useful-links__link",target:"_blank",rel:"noopener noreferrer"},[S(c(n.label)+" ",1),t[0]||(t[0]=r("span",{class:"sr-only"},"(öffnet in neuem Tab)",-1)),t[1]||(t[1]=r("span",{"aria-hidden":"true"}," ↗",-1))],8,y)]))),128))])]),_:1})]))}},G=_(P,[["__scopeId","data-v-27b4009d"]]);export{G as default};
